mapper.delete:
DELETE
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}
  AND user_id = #{userId}

mapper.update:
UPDATE visit_item
SET visit_order      = #{visitOrder},
    distance_to_next = #{distanceToNext}
WHERE visit_item_id = #{visitItemId}

UPDATE my_schedule
SET title          = #{scheduleTitle},
    start_at       = #{startAt},
    budget_details = #{budgetDetail},
    todo_details   = #{todoDetail},
    is_shared      = #{isShared}
WHERE my_schedule_id = #{scheduleId}
  AND user_id = #{userId}

UPDATE my_schedule
SET title = #{title}
WHERE my_schedule_id = #{myScheduleId}
  AND user_id = #{userId}

UPDATE my_schedule
SET todo_details = #{todoDetail}
WHERE my_schedule_id = #{scheduleId}

UPDATE my_schedule
SET budget_details = #{budgetDetail}
WHERE my_schedule_id = #{scheduleId}

UPDATE my_schedule
SET start_at = STR_TO_DATE(#{startAt}, '%Y-%m-%d')
WHERE my_schedule_id = #{scheduleId}
  AND user_id = #{userId}

UPDATE schedule_share_user
SET permission = #{permission}
WHERE my_schedule_id = #{myScheduleId}
  AND shared_user_id = #{sharedUserId}

mapper.select:
SELECT todo_details
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}

SELECT budget_details
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}

SELECT title
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}

SELECT DATE_FORMAT(start_at, '%Y-%m-%d')
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}

SELECT COUNT(my_schedule_id)
FROM my_schedule
WHERE my_schedule_id = #{id}

SELECT COUNT(my_schedule_id)
FROM my_schedule
WHERE my_schedule_id = #{scheduleId}
  AND user_id = #{userId}
